previewCss:
.darma-loader-darma-custom-119 {
  width: 50px;
  aspect-ratio: 1;
  color: #398EB6;
  background: currentColor;
  border-radius: 50%;
  position: relative;
}
.darma-loader-darma-custom-119:before {
  content: "";
  position: absolute;
  background:
    radial-gradient(farthest-side at bottom right,#0000 94%,currentColor 96%) 0    0   ,
    radial-gradient(farthest-side at bottom left ,#0000 94%,currentColor 96%) 100% 0   ,
    radial-gradient(farthest-side at top    left ,#0000 94%,currentColor 96%) 100% 100%,
    radial-gradient(farthest-side at top    right,#0000 94%,currentColor 96%) 0    100%;
  background-size: 25px 25px;
  background-repeat: no-repeat;
  animation: 
    darma-loader-darma-custom-119-l39-1 1s infinite,
    darma-loader-darma-custom-119-l39-2 1s infinite;
}
@keyframes darma-loader-darma-custom-119-l39-1 {
  0%,10%,90%,100% {inset:0}
  40%,60% {inset:-10px}
}

@keyframes darma-loader-darma-custom-119-l39-2 {
  0%,40%  {transform: rotate(0)}
  60%,100%{transform: rotate(90deg)}
}

